            <div>
              <p className="text-sm text-white font-medium">System Online</p>
              <p className="text-xs text-green-400">All services running</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

/**
 * Navbar component for top navigation
 */
const Navbar = () => {
  const [showDropdown, setShowDropdown] = useState(false);

  return (
    <div className="bg-gray-800/50 backdrop-blur-sm border-b border-gray-700 p-4 ml-64">
      <div className="flex justify-between items-center">
        <div className="flex items-center gap-4">
          <h1 className="text-2xl font-semibold bg-gradient-to-r from-blue-400 to-purple-400 bg-clip-text text-transparent">
            Unified Operations Dashboard
          </h1>
        </div>
        <div className="flex items-center gap-4">
          {/* Search */}
          <div className="relative hidden md:block">
            <input
              type="text"
              placeholder="Search..."
              className="bg-gray-700/50 text-white px-4 py-2 pl-10 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 w-64"
            />
            <svg className="w-5 h-5 absolute left-3 top-2 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
